14\uAE4C\uC9C0 \uB2F4\uB294 \uC11C\uBE44\uC2A4?\n-> \uB2E8\uC21C\uD788 \uD0AC\uB9C1\uD30C\uD2B8\uB97C \uB4F1\uB85D\uD558\uACE0, \uC0AC\uB78C\uB4E4\uC774 \uC640\uC11C \uD0AC\uB9C1\uD30C\uD2B8\uB97C \uBCFC \uC218 \uC788\uB294 \uC11C\uBE44\uC2A4 => \uC774\uBC88\uC5D0 \uC870\uD68C\uB97C \uD558\uAC8C \uB418\uBA74 \uB4F1\uB85D\uACFC \uC870\uD68C\uB97C \uD558\uBA74 \uC774 \uBD80\uBD84\uC740 \uCDA9\uC871\uC774 \uB41C\uB2E4."), mdx("p", null, "\uB4F1\uB85D\uACFC \uC870\uD68C\uB97C \uBA54\uC778\uC73C\uB85C \uC0DD\uAC01\uD55C\uB2E4\uBA74 \uC65C \uB4F1\uB85D\uC744 \uD560\uAE4C?\n\uB4F1\uB85D \uACFC\uC815\uC5D0\uC11C \uAC00\uCE58(\uB9CC\uC871\uAC10)\uB97C \uBD80\uC5EC\uD574\uC8FC\uAE30 \uC704\uD574\uC11C \uACF5\uC720\uAC00 \uB4F1\uC7A5\uD588\uB294\uB370, \uCEE4\uC9C0\uB294 \uB290\uB08C\uC774\uB2E4.\n-> \uC2E4\uC81C\uB85C \uB4E3\uB294 \uC0AC\uB78C\uB4E4\uC774 \uB9CC\uB4DC\uB294 \uD0AC\uB9C1\uD30C\uD2B8\n-> \uAE30\uC874\uC758 \uACF5\uC720\uB294 \uD30C\uD2B8\uB97C \uACF5\uC720\uD55C \uAC8C \uC544\uB2C8\uB77C \uB0B4\uAC00 \uB4F1\uB85D\uD55C \uC815\uBCF4\uB97C \uACF5\uC720\uD560 \uBFD0\uC774\uB2E4.\n-> \uB370\uBAA8\uB9CC \uBD24\uC744 \uB54C\uB294 \uD398\uC774\uC9C0\uAC00 \uC544\uB2C8\uB77C \uD50C\uB808\uC774\uD560 \uC218 \uC788\uB294 url\uC744 \uACF5\uC720\uD55C \uAC83 \uC544\uB2CC\uAC00? => \uC6B0\uB9AC\uAC00 \uC774 \uD30C\uD2B8\uB97C \uB4E4\uC5B4\uBCF4\uB77C\uACE0 \uD588\uC9C0, \uC774 \uD30C\uD2B8\uC5D0 \uB300\uD55C \uC815\uBCF4\uB97C \uC900 \uAC83\uC774 \uC544\uB2C8\uB2E4. \uB530\uB77C\uC11C \uD30C\uD2B8\uC5D0 \uB300\uD55C \uC815\uBCF4\uB97C \uAC16\uACE0 \uC788\uC744 \uD544\uC694 \uC5C6\uB2E4. "), mdx("p", null, "\uBE44\uD68C\uC6D0\uC774 \uB2E4 \uC870\uD68C\uB97C \uD560 \uC218 \uC788\uAC8C \uB9CC\uB4E4\uAC70\uBA74, \uD68C\uC6D0\uC740 \uC5B4\uB5A4 \uD50C\uB85C\uC6B0\uB97C \uAC00\uC9C8 \uAC83\uC778\uAC00.", mdx("br", {
    parentName: "p"
  }), "\n", "\uD68C\uC6D0\uC774 \uC870\uD68C\uAC00 \uAC00\uB2A5\uD558\uB2E4\uBA74 \uB9CC\uC871\uAC10\uC744 \uAC00\uC9C8 \uC218 \uC788\uC744 \uAC83\uC778\uAC00?"), mdx("p", null, "\uD68C\uC6D0\uC774 \uB4F1\uB85D \uC804\uC5D0 \uC870\uD68C\uB97C \uD558\uBA74 \uB9CC\uC871\uAC10\uC744 \uC5BB\uC744 \uC218 \uC5C6\uB2E4."), mdx("hr", null), mdx("p", null, "\uD0AC\uB9C1\uD30C\uD2B8\uB294 \uB0B4\uAC00 \uC88B\uC544\uD558\uB294 \uBD80\uBD84\uC774 \uC544\uB2C8\uB77C, \uC0AC\uB78C\uB4E4\uC774 \uC88B\uC544\uD558\uB294 \uBD80\uBD84\uC774\uB2E4."), mdx("p", null, "\uB0B4\uAC00 \uC88B\uC544\uD558\uB294 \uBD80\uBD84\uC744 \uACF5\uC720\uD558\uACE0 \uC2F6\uC740 \uC0AC\uB78C\n\uC0AC\uB78C\uB4E4\uC774 \uC88B\uC544\uD558\uB294 \uBD80\uBD84\uC744 \uC54C\uACE0 \uC2F6\uC740 \uC0AC\uB78C"));
